const Q_GOVERNMENT_1994=[{"id": "objective>Government>1994>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A society that is politically organized under a government is called a <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sovereign state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">community</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> nation state</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> polity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A polity can be any other group of people organized for governance (such as a corporate board), the government of a country, or of a country subdivision. A polity may be a republic administered by an elected representative, or the realm of a hereditary monarch.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : SOCIETY, STATE, NATION AND NATION-STATE"}, {"id": "objective>Government>1994>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Political power is naked force when it is exercised without</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">set objectives</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> state apparatus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">governmental legitimacy</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> sovereignty</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Political power is naked force when it is exercised without governmental legitimacy. Governmental legitimacy is the popular acceptance of an authority, usually a governing law or a regime. Without legitimacy, the actions and decrees of a ruler, a government, or other authority figure may be seen as arbitrary and lacking moral, ethical, or legal foundations.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POWER, AUTHORITY, LEGITIMACY AND SOVEREIGNTY"}, {"id": "objective>Government>1994>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major different between a state and a nation is that the latter presupposes a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heterogenous population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">homogenous population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">well defined territory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more organized system</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A nation presupposes a homogenous population. This means that a nation is a group of people who share common cultural, ethnic, or linguistic ties. A state, on the other hand, is a political entity with a defined territory and government, and it can include a diverse, or heterogeneous, population.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : SOCIETY, STATE, NATION AND NATION-STATE"}, {"id": "objective>Government>1994>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of judicial independence makes sense only when judges</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> have freedom to try any case</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are thermselves above the law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have permanent tenure of office</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can join any political party of their choice</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of judicial independence makes sense only when judges have permanent tenure of office. This is because judicial independence refers to the concept that judges should be able to decide cases impartially and without interference from the other branches of government or from private or political interests. Permanent tenure helps to ensure this independence by protecting judges from dismissal based on their decisions.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>1994>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A federal system of government has the following three advantages</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">economies of scale, uniform development and political unity</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> economies of scale, uniform development and strong army</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> strong army, greater security and economies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic co-operation, uniform development and greater security</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A federal system of government is a type of government where power is divided between a central government and individual states or provinces. The advantages of a federal system of government include economic cooperation, uniform development, and greater security. Economic cooperation refers to the ability of different states or provinces to work together for economic growth. Uniform development refers to the equal development of all states or provinces, ensuring that no area is left behind. Greater security refers to the ability of the central government to provide security for all states or provinces.</div>", "topic": "STRUCTURES OF GOVERNANCE : FEDERAL FEATURES, REASONS FOR ADOPTION, MERITS AND DEMERITS"}, {"id": "objective>Government>1994>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Constitutionalism means</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">promotion of the constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respect for the constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> electoral processes based on the constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">voting rule and regulations</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Constitutionalism can be defined as the doctrine that governs the legitimacy of government action, and it implies something far more important than the idea of legality that requires official conduct to be in accordance with pre-fixed legal rules.</div>", "topic": "PRINCIPLES OF DEMOCRATIC GOVERNMENT : CONSTITUTIONALISM, RULE OF LAW AND REPRESENTATIVE GOVERNMENT"}, {"id": "objective>Government>1994>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Switzerland is often cited as a classic example of a country with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unitary constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quasi unitary constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> federal constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">confederal constitution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Switzerland is often cited as a classic example of a country with a federal constitution. A federal constitution is a system of government where powers are divided between a central government and regional or state governments. Each level of government has its own jurisdiction and autonomy. Switzerland is a federation of 26 cantons, each with its own constitution, legislature, government and courts.</div>", "topic": "STRUCTURES OF GOVERNANCE : FEDERAL FEATURES, REASONS FOR ADOPTION, MERITS AND DEMERITS"}, {"id": "objective>Government>1994>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the major distinguishing characteristic between flexible and rigid constitutions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manner of documentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one is unwritten</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> amendment procedure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">degree of legality</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major distinguishing characteristic between flexible and rigid constitutions is the amendment procedure. A flexible constitution can be amended through the same process as any other law, while a rigid constitution requires a more difficult process, often involving supermajorities in the legislature or referendums. This is designed to ensure stability and prevent arbitrary changes to the constitution.</div>", "topic": "CONSTITUTION : MEANING, SOURCES AND FUNCTIONS OF CONSTITUTION"}, {"id": "objective>Government>1994>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best defines democracy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Government based on virtuous principles and laws</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government based on the spirit and letter of the constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government based on the free consent of the governed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government which recognizes and respects human rights as enshrined in the constitution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Democracy is a form of government in which power is vested in the people, who rule either directly or through freely elected representatives. It is based on the free consent of the governed, meaning that the citizens of the country have the freedom to choose their leaders in free and fair elections.</div>", "topic": "FORMS OF GOVERNMENT : DEMOCRACY FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>1994>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An economic system in which the major means of production are owned and controlled by a few individuals is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">socialism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capitalism</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capitalism is an economic system in which the major means of production are owned and controlled by a few individuals or corporations. These owners control the production and distribution of goods and services, and they operate for profit. The other options, socialism and communism, are systems where the means of production are owned and controlled by the state or community, not individuals.</div>", "topic": "POLITICAL IDEOLOGIES : CAPITALISM"}, {"id": "objective>Government>1994>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The essence of checks and balances is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enhance the functioning of government and prevent arbitary use of power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure that people have their own rights</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make sure that power is not delegated to other bodies or individuals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent political parties from putting pressure on government</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The concept of checks and balances is a fundamental principle in democratic governance. It is designed to prevent the concentration of power in one branch of government and to protect the rights and liberties of citizens. It does this by ensuring that each branch of government can limit, or check, the power of the other branches. This prevents any one branch from becoming too powerful and ensures that all branches are accountable to each other. Therefore, the essence of checks and balances is to enhance the functioning of government and prevent arbitrary use of power.</div>", "topic": "PRINCIPLES OF DEMOCRATIC GOVERNMENT : SEPARATION OF POWER, CHECKS AND BALANCES AND INDIVIDUAL/COLLECTIVE RESPONSIBILITY"}, {"id": "objective>Government>1994>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The power of a head of state to dissolve the legislature and order a general election is usually associated with the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">presidential system of government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monarchical system of government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parliamentary system of government</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> unitary system of government</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a parliamentary system, such as the United Kingdom or India, the head of state usually has mostly ceremonial powers, with a separate head of government.</div>", "topic": "SYSTEMS OF GOVERNANCE : PARLIAMENTARY SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>1994>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Accountability in public office means that officers shall</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">keep proper account of state finances</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> render good account of their activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not accept bribes and gratification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">declare their assets periodically</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Accountability in public office refers to the obligation of public officers to report, explain and be answerable for the result of their actions. It means they should render good account of their activities, showing how they have used public resources and the outcomes of their actions.</div>", "topic": "PRINCIPLES OF DEMOCRATIC GOVERNMENT : ETHICS AND ACCOUNTABILITY IN PUBLIC OFFICE"}, {"id": "objective>Government>1994>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The act of bringing a legislative session to an end only for business to continue later is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adjournment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prorogation</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> resolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">abrogation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To end a session of a Parliament, and all business then on the agenda, until it is summoned to reconvene.</div>", "topic": "PROCESSES OF LEGISLATION : LEGISLATIVE ENACTMENTS - ACTS, EDICTS AND BYE LAWS"}, {"id": "objective>Government>1994>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following violates the principle of the rule of law?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">arbitrary increase of prices by the press</div>", "<div style=\"font-family:Cambria;font-size:17px;\">criticism of government actions by the press</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arbitrariness of government policies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arbitrariness of individuals in the society</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of the rule of law states that every person is subject to the law, including people who are lawmakers, law enforcement officials, and judges. In this context, the rule of law is defined as the absolute supremacy or predominance of regular law as opposed to the influence of arbitrary power or wide discretionary power. Therefore, arbitrariness of government policies violates the principle of the rule of law because it implies the use of power without predictable and known standards.</div>", "topic": "PRINCIPLES OF DEMOCRATIC GOVERNMENT : CONSTITUTIONALISM, RULE OF LAW AND REPRESENTATIVE GOVERNMENT"}, {"id": "objective>Government>1994>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electoral system which restricts voting rights to only male adults is termed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">popular franchise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">male suffrage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adult suffrage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited franchise</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Male suffrage is a form of voting rights in which all adult male citizens within a political system are allowed to vote.</div>", "topic": "THE ELECTORAL PROCESS : SUFFRAGE – EVOLUTION, TYPES"}, {"id": "objective>Government>1994>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best represents duties and obligations of government?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">national sysmbols</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of public utilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">care of public property</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> obedience of laws</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The duties and obligations of a government primarily involve the provision of public utilities. This includes services like water supply, electricity, waste disposal, public transportation, and other infrastructure. National symbols, care of public property, and obedience of laws are not primary duties of the government, but rather symbols of national identity, responsibilities of citizens, and outcomes of effective governance respectively.</div>", "topic": "CITIZENSHIP : DUTIES AND OBLIGATIONS OF THE STATE"}, {"id": "objective>Government>1994>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electoral process in which candidates for elective offices are selected by party members is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">primary election</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electoral college</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct election</div>", "<div style=\"font-family:Cambria;font-size:17px;\">preferential voting</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Primary elections, or direct primary are a voting process by which voters can indicate their preference for their party's candidate</div>", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES – DEFINITION, ORGANIZATION, FUNCTIONS."}, {"id": "objective>Government>1994>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle that allows a representative's tenure brought to an end by his constituency is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rejection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reference</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> recall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">return</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This  is a procedure by which, in certain polities, voters can remove an elected official from office through a referendum before that official's term of office has ended. </div>", "topic": "PRINCIPLES OF DEMOCRATIC GOVERNMENT : CONSTITUTIONALISM, RULE OF LAW AND REPRESENTATIVE GOVERNMENT"}, {"id": "objective>Government>1994>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the main functions of a political party is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political evaluation</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> interest aggregation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political accountability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest determination</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the main functions of a political party is interest aggregation. Interest aggregation is the activity in which the demands of the citizens are combined and streamlined to form a coherent set of policy proposals. This is usually done by political parties, who then present these proposals to the electorate in the form of a political program.</div>", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES – DEFINITION, ORGANIZATION, FUNCTIONS."}, {"id": "objective>Government>1994>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following traditional Nigerian societies practiced the system of checks and balances?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tiv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yoruba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hausa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Igbo</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Yoruba traditional society practiced the system of checks and balances. In the Yoruba traditional political system, the Oba (king) was the head of the state, but his powers were checked by a council of chiefs known as the Oyomesi. The Oyomesi had the power to check the Oba's authority and could force him to commit suicide if they felt he was ruling unjustly. This system ensured a balance of power and prevented the Oba from becoming a dictator.</div>", "topic": "PRE-COLONIAL POLITICS : OTHER PRE-COLONIAL SYSTEMS IN NIGERIA"}, {"id": "objective>Government>1994>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In terms of administrative structure, which of the following sets of pre-colonial Nigerian political systems do NOT match?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Igbo and Tiv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benin and Igbo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sokoto and OYO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benin and Sokoto</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The administrative structures of the Igbo and Tiv political systems do not match. The Igbo operated a decentralized system of government with no centralized authority, while the Tiv had a slightly centralized system with the Tiv elders having some level of authority. The other pairs (Benin and Igbo, Sokoto and Oyo, Benin and Sokoto) had similar administrative structures in terms of centralization.</div>", "topic": "PRE-COLONIAL POLITICS : IGBO PRE-COLONIAL SYSTEM~~PRE-COLONIAL POLITICS : HAUSA PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>1994>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nationalist activities were earlier in British than in French West Africa because the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">French West Africans were not interested in having self government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">British colonialists were no longer interested in governing their acquired territories</div>", "<div style=\"font-family:Cambria;font-size:17px;\">French addministrative polices did not allow for poltical agitation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nationalists their french counterparts</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The French administrative policies did not allow for political agitation. This means that the French colonial government had strict policies that suppressed any form of political agitation or nationalist activities.</div>", "topic": "IMPERIALIST PENETRATION : THE BRITISH COLONIAL ADMINISTRATIVE POLICY – DIRECT AND INDIRECT RULE"}, {"id": "objective>Government>1994>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In British West Africa, the elective principle was first introduced in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Ghana</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Sierra Leone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Gambia</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Through the Clifford's constitution of 1922. This is the accurate answer. <br/> </div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : HUGH CLIFFORD CONSTITUTION 1922"}, {"id": "objective>Government>1994>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A throny issue during the 1957/58 Nigerian constitutional conferences was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leadership of the first post-independence government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">problem of ethnic minorities</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> control of the mid - west by the western region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">status of lagos</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the 1957/58 Nigerian constitutional conferences, the problem of ethnic minorities was a thorny issue. This was because the minorities were afraid of being dominated by the major ethnic groups in the country. They demanded for states of their own to protect their interests. None of the other options presented were major issues during the conferences.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : INDEPENDENCE CONSTITUTION 1960"}, {"id": "objective>Government>1994>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the 1963 Constitution, there was separation of powers between the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">president and the commander in chief of the armed forces</div>", "<div style=\"font-family:Cambria;font-size:17px;\">executive and the legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">head of state and the president</div>", "<div style=\"font-family:Cambria;font-size:17px;\">head of government and the head of state</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The 1963 Constitution of Nigeria, also known as the Republican Constitution, established the principle of separation of powers between the executive and the legislature. This means that the executive cannot interfere with the legislative functions and vice versa. The other options do not accurately represent the separation of powers as outlined in the 1963 Constitution.</div>", "topic": "POST - INDEPENDENCE CONSTITUTIONS : 1963 CONSTITUTION CHARACTERISTICS AND SHORTCOMINGS"}, {"id": "objective>Government>1994>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major feature whch differentiated the 1963 and 1979 constitutions was that in the former,</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ministers were appointed from the national assembly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ministers were appointed from outside the national assembly</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> the prime minister was elected by the whole country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the national assembly comprised the senate and the house of assembly</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The 1963 constitution of Nigeria provided for a parliamentary system of government where ministers were appointed from the national assembly. This is different from the 1979 constitution which provided for a presidential system of government where ministers could be appointed from outside the national assembly.</div>", "topic": "POST - INDEPENDENCE CONSTITUTIONS : 1979 CONSTITUTION CHARACTERISTICS AND SHORTCOMINGS"}, {"id": "objective>Government>1994>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A court order compelling the executive or its agencies to produce an unlawfully detained person is called a writ of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mandamus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subpoena <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> habeas corpus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">injunction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The \"Great Writ\" of habeas corpus is a fundamental right in the Constitution that protects against unlawful and indefinite imprisonment. </div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>1994>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary function of the Armed Forces of Nigeria is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">promote and protect the security of the nation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the head of state and commander in chief of the armed forces of the nation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the citizens against corrupt and oppressive politicians</div>", "<div style=\"font-family:Cambria;font-size:17px;\">project the country's image by participating in peace keeping operations</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary function of the Armed Forces of Nigeria is to promote and protect the security of the nation. This is because the Armed Forces are responsible for defending the country from external aggression, maintaining its territorial integrity and promoting peace and security within its borders.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>1994>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which organ was enshrined in the 1979 Constitution to protect public servants form political interference and arbitrary dismissal?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public complaints commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">code of conduct bureau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">federal judicial service commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">federal civil service commission</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A civil service commission is a government agency that is constituted by legislature to regulate the employment and working conditions of civil servants, oversee hiring and promotions, and promote the values of the public service.</div>", "topic": "PUBLIC COMMISSIONS ESTABLISHED BY THE 1979 AND SUBSEQUENT CONSTITUTIONS : THE CIVIL SERVICE COMMISSION"}, {"id": "objective>Government>1994>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The political party that replaced NNDP before independence was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NYM</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NCNC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">UNDP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AG</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The party continued to dominate politics in Lagos until 1938, when the Nigerian Youth Movement (NYM) overtook it in elections.</div>", "topic": "POLITICAL PARTIES AND PARTY POLITICS IN POST-INDEPENDENCE NIGERIA : FIRST REPUBLIC"}, {"id": "objective>Government>1994>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Apart from discussing the draft of the 1979 constitution, what was the major pre- occupation of the constituent assembly in 1978?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">revenue allocation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sharia issue</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> formation of political parties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">election of a president</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Apart from discussing the draft of the 1979 constitution, the major pre-occupation of the constituent assembly in 1978 was revenue allocation. Revenue allocation is the distribution of revenue, derived from the country's resources, among the various levels of government in a country. In Nigeria, the issue of revenue allocation has been a major problem particularly since the discovery and exploration of oil.</div>", "topic": "POST - INDEPENDENCE CONSTITUTIONS : 1979 CONSTITUTION CHARACTERISTICS AND SHORTCOMINGS"}, {"id": "objective>Government>1994>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first minority state to be created in the Nigerian federation was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Benue Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cross River</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kwara</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mid-West</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first minority state to be created in the Nigerian federation was the Mid-West region in 1963. The creation of the Mid-West region was to address the fears of the minority ethnic groups in the Western region that they were being dominated by the majority Yoruba ethnic group.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : CREATION OF STATES – 1963, 1967, 1976, 1987, 1991, 1996"}, {"id": "objective>Government>1994>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One major constraint on the smooth operation of federalism in Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tack of an acceptable revenue allocation formula</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inability to conduct a successful census</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high cost of administration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frequent change of government</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One major constraint on the smooth operation of federalism in Nigeria is the lack of an acceptable revenue allocation formula. Federalism is a system of government where power is divided between a central authority and constituent political units. In Nigeria, the issue of how to allocate revenue among the federal, state, and local governments has been a major source of conflict and instability. This is because the revenue allocation formula determines the amount of resources available to each level of government to carry out its responsibilities.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : PROBLEMS OF NIGERIAN FEDERALISM – CENSUS, REVENUE ALLOCATION, CONFLICTS ETC"}, {"id": "objective>Government>1994>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the based differences between ministries and public corporations is that while ministries are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">run on rules, public corporations are not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wholly owned by the government, public corporations are owned by both government and individual</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not established with specific statutes public corporations are</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not important in developmental process, public corporations are</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ministries are wholly owned by the government, they are part of the government's administrative structure and are funded by the government. On the other hand, public corporations can be owned by both the government and individuals. Public corporations are created by the government to undertake commercial activities on its behalf. They can issue shares to the public to raise capital, hence, they can be owned by both the government and individuals.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS : DEFINITION, TYPES, PURPOSE AND FUNCTIONS"}, {"id": "objective>Government>1994>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization and commercialization of public enterprises in Nigeria will lead to further entrenchment of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">socialism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capitalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">welfarism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fascism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization and commercialization of public enterprises in Nigeria will lead to further entrenchment of capitalism. Capitalism is an economic system where private entities own the factors of production. The four factors are entrepreneurship, capital goods, natural resources, and labor. The owners of capital goods, natural resources, and entrepreneurship exercise control through companies. Privatization is a key part of this system as it involves transferring ownership of a business, enterprise, agency, public service or public property from the public sector, which is the government, to the private sector, which includes businesses and private individuals.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS : DEREGULATION, PRIVATIZATION, COMMERCIALIZATION – OBJECTIVES, FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>1994>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The 1976 Local Government Reforms has</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduced political corruption at the local level</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> resulted in accelerated development in the rural areas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">created more autonomy for local administration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced the political roles of traditional rulers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The 1976 Local Government Reforms in Nigeria were aimed at creating more autonomy for local administration. The reforms were designed to decentralize power and give local governments more control over their affairs. This was done by granting them legal and financial autonomy, and the power to make decisions on certain local issues. The reforms did not necessarily reduce political corruption at the local level or result in accelerated development in rural areas. Also, the political roles of traditional rulers were not significantly reduced by these reforms.</div>", "topic": "LOCAL GOVERNMENT :FEATURES OF LOCAL GOVERNMENT REFORMS 1976, 1989 - STRUCTURE, FUNCTIONS, FINANCE AND INTER-GOVERNMENTAL RELATIONS"}, {"id": "objective>Government>1994>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Babangida administration's transition to civil rule programme officially started in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1992</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1990</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1986</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1987</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Babangida announced early in 1986 that a civilian government would be formed by 1990, later extending the date by two years to allow more time for preparation.</div>", "topic": "POLITICAL PARTIES AND PARTY POLITICS IN POST-INDEPENDENCE NIGERIA : THIRD REPUBLIC"}, {"id": "objective>Government>1994>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major negative impact of military intervention in Nigerian politics is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">politicization of the military</div>", "<div style=\"font-family:Cambria;font-size:17px;\">domination of the economy by foreign power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor performance of the military in foreign peace-keeping operations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neglected of he welfare of military personnel</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The politicization of the military is a major negative impact of military intervention in Nigerian politics. This is because when the military intervenes in politics, it often leads to the military becoming involved in political affairs, which can lead to a lack of neutrality and impartiality in the military. This can undermine the military's primary role of defending the nation and maintaining security, as they may be more focused on political issues and power struggles.</div>", "topic": "THE MILITARY IN NIGERIAN POLITICS : IMPACT OF MILITARY RULE"}, {"id": "objective>Government>1994>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The committee that recommended Abuja as the new Federal Capital was headed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Graham Douglas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mamman Nasir</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rotimi Williams</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Akinola Aguda</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Justice Akinola Aguda headed the committee that selected ABUJA as the Federal Capital Territory.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : RATIONALE FOR A FEDERAL SYSTEM"}, {"id": "objective>Government>1994>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term, comprador bourgeoise has been used by scholars to describe</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">foreign businessmen in Nigerian</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign diplomats working in Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian businessmen who represent foreign interests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian contractors to foreign government</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The term 'comprador bourgeoisie' is used to describe a social class in colonial countries, particularly in the context of their economic and political activities. It refers to local or indigenous members of the bourgeoisie who have close ties with foreign capitalists and serve their interests. In this context, it refers to Nigerian businessmen who represent foreign interests.</div>", "topic": "NIGERIA’S FOREIGN POLICY : RELATIONS WITH DEVELOPING COUNTRIES"}, {"id": "objective>Government>1994>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following countries is closely associated with the development of Ajaokuta Steel Project?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">U S A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Germany</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> India</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Russia</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Ajaokuta Steel Project is closely associated with Russia. The project was primarily designed and built by the Soviet Union (now Russia) in the late 1970s and early 1980s. The Soviets also provided technical assistance and training to Nigerian workers as part of the project.</div>", "topic": "NIGERIA’S FOREIGN POLICY : RELATIONS WITH MAJOR POWERS"}, {"id": "objective>Government>1994>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The foreign affairs minister who advocated the concept of medium powers' was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prof Ibrahim Gambari</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Major-General Joe Garba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alhaji Rilwanu Lukman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prof, Bolaji Akinyemi</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">He also came up with the concept of the \"Concept of Medium Powers\". In his position as Minister of External Affairs, Akinyemi headed numerous Nigerian delegations.</div>", "topic": "NIGERIA’S FOREIGN POLICY : NIGERIA’S NON-ALIGNMENT POLICY"}, {"id": "objective>Government>1994>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reasons best explains why Nigeria during the first republic, could not pursue an independent foreign policy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the numerous differences among the ethnic groups</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of political ideology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria was a non-aligned country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's economy was dependent on the Western countries</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the first republic, Nigeria could not pursue an independent foreign policy mainly because Nigeria's economy was dependent on the Western countries. An independent foreign policy refers to a policy that is designed by a nation to conduct its foreign affairs free of external influences. However, due to economic dependence, Nigeria had to align its foreign policy with the interests of its Western benefactors.</div>", "topic": "NIGERIA’S FOREIGN POLICY : RELATIONS WITH MAJOR POWERS"}, {"id": "objective>Government>1994>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The British prime minister who opposed the cancellation of Nigeria's debt was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Margaret Thatcher</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Edward Heath</div>", "<div style=\"font-family:Cambria;font-size:17px;\">John Major</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hardold Wilson</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is the correct answer as she opposed the move.</div>", "topic": "NIGERIA’S FOREIGN POLICY : RELATIONS WITH MAJOR POWERS"}, {"id": "objective>Government>1994>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following African countries receive Nigeria assistance to fight her war of independence in 1975/76?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Namibia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Angola</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mozambique</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This commitment was pursued most actively after Murtala Muhammad successfully backed the Movimento Popular de Liberta de Angola's ascent to power in Angola in 1975 by providing the swing vote in the OAU decision to recognize the MPLA.</div>", "topic": "NIGERIA IN INTERNATIONAL ORGANIZATIONS : THE AFRICAN UNION"}, {"id": "objective>Government>1994>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which Nigerian was the executive secretary of the ECA?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chief Emeka Anyaoku</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prof. Adebayo Adedeji</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chief Matthew Mbu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alhaji Abubakar Alhaji</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Professor Adebayo Adedeji is from Nigeria. He was the Under- Secretary-General and Executive Secretary of the United Nations Economic Commission for Africa (ECA) from 1975 to 1991.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS"}, {"id": "objective>Government>1994>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria was regarded as a Frontline State because she</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">assisted liberation struggles in Southern Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Assisted ECOMOG troops in liberia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sent troops for peace keeping in Somalia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sent policemen to Namibia</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria was regarded as a Frontline State because she assisted liberation struggles in Southern Africa. The term 'Frontline States' was used to refer to the group of African countries which, during the late 20th century, were leading the fight against colonialism and white minority rule. Nigeria was not geographically a frontline state but was considered as such due to its significant role in supporting the liberation movements in Southern Africa.</div>", "topic": "NIGERIA IN INTERNATIONAL ORGANIZATIONS : THE AFRICAN UNION"}, {"id": "objective>Government>1994>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major strategy used by OPEC to influence oil price is by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">determining the quantity of oil to be produced by each member state at any given period</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> influencing buyers at the international market to buy at high prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> allowing member countries to produce at their discretion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the supply of the commodity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Organization of the Petroleum Exporting Countries (OPEC) is a group consisting of 14 of the world's major oil-exporting nations. OPEC's mission is to coordinate and unify the petroleum policies of its member countries and ensure the stabilization of oil markets. They do this by adjusting their oil output to help maintain a stable price. Therefore, the major strategy used by OPEC to influence oil price is by increasing or decreasing the supply of the commodity.</div>", "topic": "NIGERIA IN INTERNATIONAL ORGANIZATIONS : THE ORGANIZATION OF PETROLEUM EXPORTING COUNTRIES-OPEC."}, {"id": "objective>Government>1994>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Gulf War of 1990 is an indication that the UNO is unable to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ensure free world trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stop colonialism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">control armament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure permanent world peace</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major purpose of U.N.O. is to keep peace throughout the world. The Gulf war was a disruption of peace, an indication that UNO is unable to ensure permanent world peace.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}];
